 33	int decode_esm_message_container(EsmMessageContainer *esmmessagecontainer, uint8_t iei, uint8_t *buffer, uint32_t len)
 34	{
 35	  int decoded = 0;
 36	  int decode_result;
 37	  uint16_t ielen;
 38	
 39	  LOG_FUNC_IN;
 40	
 41	  if (iei > 0) {
 42	    CHECK_IEI_DECODER(iei, *buffer);
 43	    decoded++;
 44	  }
 45	
 46	  DECODE_LENGTH_U16(buffer + decoded, ielen, decoded);
 47	
 48	  CHECK_LENGTH_DECODER(len - decoded, ielen);
 49	
 50	
 51	  if ((decode_result = decode_octet_string(&esmmessagecontainer->esmmessagecontainercontents, ielen, buffer + decoded, len - decoded)) < 0) {
 52	    LOG_FUNC_RETURN(decode_result);
 53	  } else {
 54	    decoded += decode_result;
 55	  }
 56	
 57	#if defined (NAS_DEBUG)
 58	  dump_esm_message_container_xml(esmmessagecontainer, iei);
 59	#endif
 60	  LOG_FUNC_RETURN(decoded);
 61	}
 62	
 63	int encode_esm_message_container(EsmMessageContainer *esmmessagecontainer, uint8_t iei, uint8_t *buffer, uint32_t len)
 64	{
 65	  uint8_t *lenPtr;
 66	  uint32_t encoded = 0;
 67	  int32_t encode_result;
 68	  /* Checking IEI and pointer */
 69	  CHECK_PDU_POINTER_AND_LENGTH_ENCODER(buffer, ESM_MESSAGE_CONTAINER_MINIMUM_LENGTH, len);
 70	#if defined (NAS_DEBUG)
 71	  dump_esm_message_container_xml(esmmessagecontainer, iei);
 72	#endif
 73	
 74	  if (iei > 0) {
 75	    *buffer = iei;
 76	    encoded++;
 77	  }
 78	
 79	  lenPtr  = (buffer + encoded);
 80	
 81	  //encoded += 2;
 82	  //if ((encode_result = encode_octet_string(&esmmessagecontainer->esmmessagecontainercontents, buffer + sizeof(uint16_t), len - sizeof(uint16_t))) < 0)
 83	  if ((encode_result = encode_octet_string(&esmmessagecontainer->esmmessagecontainercontents, lenPtr + sizeof(uint16_t), len - sizeof(uint16_t))) < 0)
 84	    return encode_result;
 85	  else
 86	    encoded += encode_result;
 87	
 88	  ENCODE_U16(lenPtr, encode_result, encoded);
 89	  return encoded;
 90	}
 91	
 92	void dump_esm_message_container_xml(EsmMessageContainer *esmmessagecontainer, uint8_t iei)
 93	{
 94	  printf("<Esm Message Container>\n");
 95	
 96	  if (iei > 0)
 97	    /* Don't display IEI if = 0 */
 98	    printf("    <IEI>0x%X</IEI>\n", iei);
 99	
100	  printf("%s", dump_octet_string_xml(&esmmessagecontainer->esmmessagecontainercontents));
101	  printf("</Esm Message Container>\n");
102	}
