 33	OctetString* dup_octet_string(OctetString *octetstring)
 34	{
 35	  OctetString *os_p = NULL;
 36	
 37	  if (octetstring) {
 38	    os_p = calloc(1,sizeof(OctetString));
 39	    os_p->length = octetstring->length;
 40	    os_p->value = malloc(octetstring->length+1);
 41	    memcpy(os_p->value, octetstring->value, octetstring->length);
 42	    os_p->value[octetstring->length] = '\0';
 43	  }
 44	  return os_p;
 45	}
 46	
 47	
 48	void free_octet_string(OctetString *octetstring)
 49	{
 50	  if (octetstring) {
 51	    if (octetstring->value) free(octetstring->value);
 52	    octetstring->value  = NULL;
 53	    octetstring->length = 0;
 54	    free(octetstring);
 55	  }
 56	}
