 59	int encode_octet_string(OctetString *octetstring, uint8_t *buffer, uint32_t buflen)
 60	{
 61	  if (octetstring != NULL) {
 62		if ((octetstring->value != NULL) && (octetstring->length > 0)) {
 63	      CHECK_PDU_POINTER_AND_LENGTH_ENCODER(buffer, (int)octetstring->length, buflen);
 64	      memcpy((void*)buffer, (void*)octetstring->value, octetstring->length);
 65	      return octetstring->length;
 66		} else {
 67		  return 0;
 68		}
 69	  } else {
 70	    return 0;
 71	  }
 72	}
