 74	int decode_octet_string(OctetString *octetstring, uint16_t pdulen, uint8_t *buffer, uint32_t buflen)
 75	{
 76	  if (buflen < pdulen)
 77	    return -1;
 78	
 79	  if ((octetstring != NULL) && (buffer!= NULL)) {
 80	    octetstring->length = pdulen;
 81	    octetstring->value = malloc(sizeof(uint8_t) * (pdulen+1));
 82	    memcpy((void*)octetstring->value, (void*)buffer, pdulen);
 83	    octetstring->value[pdulen] = '\0';
 84	    return octetstring->length;
 85	  } else {
 86	    return -1;
 87	  }
 88	}
